const port = env.get('port');
const baud = Number(env.get('baud'));
const template = env.get('command_template');
const timeoutMs = Number(env.get('timeout_ms')) || 2000;
const expected = env.get('expect_response');

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const sent = template
    .replace('{y}', now.getFullYear())
    .replace('{mo}', pad(now.getMonth() + 1))
    .replace('{d}', pad(now.getDate()))
    .replace('{h}', pad(now.getHours()))
    .replace('{mi}', pad(now.getMinutes()))
    .replace('{s}', pad(now.getSeconds()))
    .replace(/\\r/g, '\r')
    .replace(/\\n/g, '\n');

msg._sent = sent;
msg._expected = expected;

const payload = JSON.stringify(sent);
msg.payload = `sh -c 'stty -F ${port} ${baud} raw -echo && printf %s ${payload} > ${port} & timeout ${timeoutMs / 1000} cat ${port}'`;
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const received = (msg._buf || '').trim();
const success = rc === 0 && (msg._expected ? received.includes(msg._expected) : true);

msg.payload = {
    success,
    sent: msg._sent,
    received,
    exit_code: rc,
    timestamp: new Date().toISOString()
};

delete msg._sent;
delete msg._expected;
delete msg._buf;
return msg;
